@spec mm_unified_spec  src=tests/specs/mm_unified_spec.lua  loc=176  sha=bfdeb03  cases=9
@exercises midiManager (h.fm)
@surface   fm:modify, fm:byToken, fm:notes, fm:tokenOf, fm:assign, fm:ccs, fm:delete, fm:events, fm:add
@harness   mk{seed.notes, seed.ccs}, bareMM

# Intent
  Pin-tests for the unified token-keyed write/iter surface on midiManager:
    mm:add(t) → token
    mm:assign(token, t) → token'
    mm:delete(token)
    mm:events() → token, evt iterator
  
  The loc-form methods (addNote/addCC/assignNote/assignCC/deleteNote/deleteCC)
  still exist alongside in this step; tm migrates in step 4. These tests
  exercise the unified surface in isolation.

# Cases
  @case 'add(note): returns a token that resolves to the new note'  [harness]  @ 15-27
  @case 'add(cc/pb/pa/at/pc): every evType lands and is byToken-addressable'  [harness]  @ 31-47
  @case 'assign: metadata-only change preserves the token'  [harness]  @ 51-63
  @case 'assign: identity-field change retires the old token, returns the new one'  [harness]  @ 67-80
  @case 'assign: cc identity change (chan or cc#) re-keys'  [harness]  @ 84-95
  @case 'delete(token): event vanishes from byToken and from the iterators'  [harness]  @ 99-121
  @case 'delete(unknown token): silent no-op'  [harness]  @ 125-134
  @case 'events(): yields all live events as (token, evt), notes then ccs'  [harness]  @ 138-161
  @case 'add(nil) / add{} / assign(nil, t): nil-paths return nil, no crash'  [harness]  @ 165-174

# Uses (outbound edges)
  @use call midiManager.modify  @ 19,35,59,75,90,111,115,130,168
  @use call midiManager.byToken  @ 23,43,61,77,78,92,93,112,113,116,154
  @use call midiManager.notes  @ 56,72,107
