  @use call midiManager.assign  @ 59,75,90,171
  @use call midiManager.ccs  @ 87,108
  @use call midiManager.delete  @ 111,115,130,172
  @use call midiManager.events  @ 119,132,151
  @use call midiManager.add  @ 169
